INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 1.5, 101, 0.029, 110, 1, 0, 122601, 1, 160, 0, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 111, 2.5, 102, 0.014, 105, 2, 1, 122401, 2, 120, 0, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 105, 2.5, 103, 0.017, 110, 3, 0, 122501, 3, 350, 1, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 105, 1.5, 104, 0.016, 110, 4, 1, 107501, 4, 130, 0, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 2.5, 105, 0.014, 110, 5, 0, 107601, 5, 160, 0, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 103, 3.5, 106, 0.029, 120, 6, 0, 107801, 6, 255, 1, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 103, 3.5, 107, 0.013, 120, 7, 0, 110601, 7, 160, 0, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 103, 2.5, 108, 0.014, 110, 8, 0, 110401, 8, 350, 1, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 100, 1.5, 109, 0.012, 105, 9, 1, 110501, 9, 130, 0, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 103, 2.5, 110, 0.014, 105, 10, 0, 115701, 10, 200, 0, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 103, 2.5, 111, 0.071, 105, 11, 0, 113601, 11, 350, 1, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 103, 1.5, 112, 0.014, 120, 12, 1, 107901, 12, 130, 0, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 105, 1.5, 113, 0.022, 110, 13, 0, 108001, 13, 200, 0, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 108, 2.5, 114, 0.031, 110, 14, 0, 110301, 14, 160, 0, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 0.5, 115, 0.036, 110, 15, 1, 107701, 15, 130, 0, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 95, 3.5, 116, 0.048, 110, 16, 0, 113101, 16, 350, 1, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 105, 1.5, 117, 0.043, 105, 17, 1, 113301, 17, 130, 0, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 95, 1.5, 118, 0.018, 105, 18, 1, 113201, 18, 130, 0, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 108, 2.5, 119, 0.021, 110, 19, 0, 117001, 19, 160, 0, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 2.5, 120, 0.036, 110, 20, 0, 113501, 20, 255, 1, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 105, 2.5, 121, 0.02, 105, 21, 0, 113401, 21, 350, 1, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 2.5, 122, 0.018, 110, 22, 1, 110101, 22, 130, 0, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 111, 3.5, 123, 0.03, 105, 23, 0, 110001, 23, 160, 0, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 103, 1.5, 124, 0.027, 110, 24, 1, 117201, 24, 130, 0, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 108, 3.5, 125, 0.02, 105, 25, 0, 117301, 25, 160, 0, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 105, 2.5, 126, 0.04, 110, 26, 0, 117401, 26, 350, 1, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 3.5, 127, 0.009, 110, 27, 0, 117101, 27, 350, 1, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 105, 3.5, 128, 0.022, 120, 28, 0, 122901, 28, 255, 1, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 105, 2.5, 129, 0.028, 110, 29, 1, 122801, 29, 130, 0, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 108, 3.5, 130, 0.023, 105, 30, 0, 122701, 30, 130, 0, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 1);
